# Build the output JSON structure with proper label names and ensure matching substrings.
def build_output(occurrences_sorted):
    out = []
    for start, end, text, typ in occurrences_sorted:
        # assert match
        assert raw[start:end] == text, (start, end, text, raw[start-5:end+5])
        citation_type = "Hadeeth" if typ == "Hadith" else "Aya"
        out.append({
            "span_start": start,
            "span_end": end,
            "span_text": text,
            "citation_type": citation_type
        })
    return {"citations": out}

output = build_output(occurrences_sorted)
